// --- System Settings ---------------------------------------------------------

func (q *Queries) GetSystemSetting(ctx context.Context, key string) (SystemSetting, error) {
	row := q.db.QueryRow(ctx, `SELECT key, value_text, updated_at FROM system_settings WHERE key=$1`, key)
	var s SystemSetting
	err := row.Scan(&s.Key, &s.ValueText, &s.UpdatedAt)
	return s, err
}

func (q *Queries) UpsertSystemSetting(ctx context.Context, key, valueText string) (SystemSetting, error) {
	row := q.db.QueryRow(ctx,
		`INSERT INTO system_settings (key, value_text, updated_at)
		 VALUES ($1,$2,NOW())
		 ON CONFLICT (key) DO UPDATE SET value_text=EXCLUDED.value_text, updated_at=NOW()
		 RETURNING key, value_text, updated_at`,
		key, valueText)
	var s SystemSetting
	err := row.Scan(&s.Key, &s.ValueText, &s.UpdatedAt)
	return s, err
}

func (q *Queries) CreatePipelineEvent(ctx context.Context, companyID uuid.UUID, eventType string, payload json.RawMessage) (PipelineEvent, error) {
	row := q.db.QueryRow(ctx,
		`INSERT INTO pipeline_events (company_id, type, payload) VALUES ($1,$2,$3) RETURNING id, company_id, type, payload, created_at`,
		companyID, eventType, payload)
	var e PipelineEvent
	err := row.Scan(&e.ID, &e.CompanyID, &e.Type, &e.Payload, &e.CreatedAt)
	return e, err
}

func (q *Queries) ListPipelineEvents(ctx context.Context, companyID uuid.UUID) ([]PipelineEvent, error) {
	rows, err := q.db.Query(ctx, `SELECT id, company_id, type, payload, created_at FROM pipeline_events WHERE company_id=$1 ORDER BY created_at DESC`, companyID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var events []PipelineEvent
	for rows.Next() {
		var e PipelineEvent
		if err := rows.Scan(&e.ID, &e.CompanyID, &e.Type, &e.Payload, &e.CreatedAt); err != nil {
			return nil, err
		}
		events = append(events, e)
	}
	return events, rows.Err()
}
